import { BackupItem } from '@eclipse-che/common';
import { Form, ValidatedOptions } from '@patternfly/react-core';
import React, { useEffect, useState } from 'react';

import { BackupSelectorField } from '@/pages/RestoreFromBackup/SameClusterForm/BackupSelectorField';
import { ImagePreviewField } from '@/pages/RestoreFromBackup/SameClusterForm/ImagePreviewField';
import { WorkspaceNameField } from '@/pages/RestoreFromBackup/SameClusterForm/WorkspaceNameField';
import { useRestoreFormValidation } from '@/pages/RestoreFromBackup/useRestoreFormValidation';

export type SameClusterRestoreData = {
  workspaceName: string;
  imageUrl: string;
};

type Props = {
  backups: BackupItem[];
  onValidationChange: (isValid: boolean, data: SameClusterRestoreData | null) => void;
  actionButton: React.ReactNode;
};

export const SameClusterRestoreForm: React.FC<Props> = ({
  backups,
  onValidationChange,
  actionButton,
}) => {
  const [selectedBackup, setSelectedBackup] = useState<BackupItem | undefined>(undefined);

  const {
    workspaceName,
    workspaceNameValidated,
    workspaceNameError,
    setWorkspaceName,
    handleWorkspaceNameChange,
  } = useRestoreFormValidation();

  // Determine validity and notify parent
  useEffect(() => {
    const nameConflict =
      selectedBackup?.workspaceExists && workspaceName === selectedBackup.workspaceName;
    const isValid = workspaceNameValidated === ValidatedOptions.success && !nameConflict;

    const imageUrl = selectedBackup ? selectedBackup.imageUrl : '';

    if (isValid) {
      onValidationChange(true, { workspaceName, imageUrl });
    } else {
      onValidationChange(false, null);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedBackup, workspaceName, workspaceNameValidated]);

  const handleBackupChange = (backup: BackupItem | undefined) => {
    setSelectedBackup(backup);
    if (backup) {
      setWorkspaceName(backup.workspaceName);
    }
  };

  const imageUrl = selectedBackup ? selectedBackup.imageUrl : '';

  return (
    <Form isHorizontal={true} onSubmit={e => e.preventDefault()}>
      <BackupSelectorField
        backups={backups}
        selectedBackup={selectedBackup}
        workspaceName={workspaceName}
        onChange={backup => handleBackupChange(backup)}
      />

      <WorkspaceNameField
        value={workspaceName}
        validated={workspaceNameValidated}
        error={workspaceNameError}
        onChange={value => handleWorkspaceNameChange(value)}
        actionButton={actionButton}
      />

      <ImagePreviewField imageUrl={imageUrl} />
    </Form>
  );
};
